// --- Path: battleClaims/$claimId ---

export interface BattleClaimsRequest {
  battleId: string;
  winner: AddressType;
  betAmountMicro: number | TimeOperation | IncrementOperation | TokenAmount;
  claimedAt: number | TimeOperation | IncrementOperation | TokenAmount;
}

export interface BattleClaimsResponse {
  battleId: string;
  winner: string;
  betAmountMicro: number;
  claimedAt: number;
  id: string;
  tarobase_created_at: number;
  tarobase_transaction_hash?: string | undefined; // Represents the hash of the transaction that created this item. Can be used to create Solscan links (combine with the current network in the Tarobase app)
}

/**
 * Build a BattleClaims operation for use with setMany.
 * @returns A DocumentOperation that can be passed to setMany.
 */
export function buildBattleClaims(claimId: string, data?: BattleClaimsRequest): DocumentOperation {
  const doc = data ? transformValues(data) : {};
  return { path: `battleClaims/${claimId}`, document: doc };
}

/**
 * Backend-only (PROJECT_VAULT_ADDRESS). The backend determines the winner by querying Phoenix PnL for both participants, updates battles.$battleId.winner, then creates this claim with winner = winning wallet, betAmountMicro = the battle's bet amount, and $claimId = battleId (one claim per battle). Onchain hook performs an ATOMIC two-step transfer from the battle PDA (battleId is the PDA account ID, the program signs for it): (1) transfers 98% of the total pot — (2 * betAmountMicro * 98) / 100 USDC — to @newData.winner, and (2) transfers 2% platform fee — (2 * betAmountMicro * 2) / 100 USDC — to @constants.ADMIN_ADDRESS. Both transfers must succeed (chained with &&) — if either fails the entire claim is rolled back. Integer math: multiply before divide to avoid precision loss (1 micro-USDC rounding error possible on odd pots). Backend should also update battles.status to 'claimed' after this succeeds. (Create/Update Single Item)
 * @returns A boolean indicating whether the operation succeeded (true) or failed (false). Always check this value to confirm the write worked.
 */
export async function setBattleClaims(claimId: string, data?: BattleClaimsRequest): Promise<boolean> {
  try {
    const transformedData = transformValues(data || {});
    const succeeded = await set(`battleClaims/${claimId}`, transformedData);
    return !!succeeded;
  } catch (error) {
    console.error(`Error setting BattleClaims: ${formatError(error)}`);
    return false;
  }
}

/**
 * 
  Read Operation Details: Public (onchain). Anyone can read claim records.
   (Get Single Item)
 */
export async function getBattleClaims(claimId: string): Promise<BattleClaimsResponse | null> {
  try {
    const result = await get(`battleClaims/${claimId}`);
    return result as BattleClaimsResponse | null;
  } catch (error) {
    console.error(`Error getting BattleClaims: ${formatError(error)}`);
    return null;
  }
}

