  potAccountId: string;
  rank: number;
  winner: string;
  claimed: boolean;
  mint1?: string;
  amt1: number;
  mint2?: string;
  amt2: number;
  mint3?: string;
  amt3: number;
  mint4?: string;
  amt4: number;
