/**
 * Build a MonthlyRewardAllotment update operation for use with setMany.
 * @returns A DocumentOperation that can be passed to setMany.
 */
export function buildUpdateMonthlyRewardAllotment(allotmentId: string, data: MonthlyRewardAllotmentRequestUpdate): DocumentOperation {
  const doc = transformValues(data);
  return { path: `monthlyRewardAllotment/${allotmentId}`, document: doc };
}

/**
 * Winner-signed claim — the ONE transaction. Caller must equal @data.winner and the doc must be unclaimed (@data.claimed == false). The update may ONLY flip claimed false->true; winner, potAccountId and every amtN are required to be unchanged (prevents tampering with the baked amounts). Onchain hook (atomic, single approval): (1) transfers the flat MONTHLY_REWARD_CLAIM_FEE_LAMPORTS (0.01 test-SOL) from the WINNER (@user.address, who signs) to @constants.REWARD_FEE_WALLET; (2) for each of the 5 slots, if amtN > 0 transfers amtN of mintN from the pot PDA (@data.potAccountId — the program signs for it) to @data.winner, and if amtN == 0 it is a safe no-op that does not abort the chain. All transfers succeed-or-roll-back together. Setting claimed=true in the same update guarantees exactly-once (a second update fails the @data.claimed == false guard). Frontend must send a FULL update preserving winner/potAccountId/amtN unchanged and only setting claimed=true. (Update Single Item)
 * @returns A boolean indicating whether the operation succeeded (true) or failed (false). Always check this value to confirm the update worked.
 */
export async function updateMonthlyRewardAllotment(allotmentId: string, data: MonthlyRewardAllotmentRequestUpdate): Promise<boolean> {
  try {
    const transformedData = transformValues(data);
    const succeeded = await set(`monthlyRewardAllotment/${allotmentId}`, transformedData);
    return !!succeeded;
  } catch (error) {
    console.error(`Error updating MonthlyRewardAllotment: ${formatError(error)}`);
    return false;
  }
}

